{"word":"l'âne","level":"A2","en":"donkey","ru":"осёл","de":"der Esel","tr":"eşek","es_ar":"el burro","it":"l'asino","ar_sy":"الحمار","examples":[{"fr":"L'âne porte un lourd sac.","en":"The donkey carries a heavy sack.","ru":"Осёл несёт тяжёлый мешок.","de":"Der Esel trägt einen schweren Sack.","tr":"Eşek ağır bir çuval taşıyor.","es_ar":"El burro carga una bolsa pesada.","it":"L'asino porta un sacco pesante.","ar_sy":"الحمار عم يشيل كيس تقيل."},{"fr":"L'âne se repose à l'ombre.","en":"The donkey rests in the shade.","ru":"Осёл отдыхает в тени.","de":"Der Esel ruht im Schatten.","tr":"Eşek gölgede dinleniyor.","es_ar":"El burro descansa a la sombra.","it":"L'asino riposa all'ombra.","ar_sy":"الحمار عم يرتاح بالفيّ."}],"topics":["animals"]},
{"word":"la biche","level":"B1","en":"doe (female deer)","ru":"лань","de":"das Reh","tr":"dişi geyik","es_ar":"la cierva","it":"la cerva","ar_sy":"الغزالة","examples":[{"fr":"Une biche traverse la forêt.","en":"A doe crosses the forest.","ru":"Лань пересекает лес.","de":"Ein Reh läuft durch den Wald.","tr":"Bir dişi geyik ormanı geçiyor.","es_ar":"Una cierva cruza el bosque.","it":"Una cerva attraversa la foresta.","ar_sy":"في غزالة عم تعبر الغابة."},{"fr":"La biche est très craintive.","en":"The doe is very timid.","ru":"Лань очень пугливая.","de":"Das Reh ist sehr scheu.","tr":"Dişi geyik çok ürkektir.","es_ar":"La cierva es muy asustadiza.","it":"La cerva è molto timida.","ar_sy":"الغزالة كتير جفولة."}],"topics":["animals"]},
{"word":"le poney","level":"A2","en":"pony","ru":"пони","de":"das Pony","tr":"midilli","es_ar":"el poni","it":"il pony","ar_sy":"الحصان الصغير (بوني)","examples":[{"fr":"Les enfants montent sur un poney.","en":"The children ride a pony.","ru":"Дети катаются на пони.","de":"Die Kinder reiten auf einem Pony.","tr":"Çocuklar midilliye biniyor.","es_ar":"Los chicos montan un poni.","it":"I bambini vanno sul pony.","ar_sy":"الولاد عم يركبوا عالبوني."},{"fr":"Ce poney est petit et doux.","en":"This pony is small and gentle.","ru":"Этот пони маленький и ласковый.","de":"Dieses Pony ist klein und sanft.","tr":"Bu midilli küçük ve uysal.","es_ar":"Este poni es chiquito y manso.","it":"Questo pony è piccolo e docile.","ar_sy":"هالبوني صغير وأليف."}],"topics":["animals"]},
{"word":"le hamster","level":"A2","en":"hamster","ru":"хомяк","de":"der Hamster","tr":"hamster","es_ar":"el hámster","it":"il criceto","ar_sy":"الهامستر","examples":[{"fr":"Le hamster court dans sa roue.","en":"The hamster runs in its wheel.","ru":"Хомяк бегает в колесе.","de":"Der Hamster läuft in seinem Rad.","tr":"Hamster çarkında koşuyor.","es_ar":"El hámster corre en su rueda.","it":"Il criceto corre nella sua ruota.","ar_sy":"الهامستر عم يركض بدولابو."},{"fr":"Le hamster garde des graines dans ses joues.","en":"The hamster keeps seeds in its cheeks.","ru":"Хомяк хранит семечки за щеками.","de":"Der Hamster bewahrt Körner in den Backen auf.","tr":"Hamster tohumları yanaklarında saklıyor.","es_ar":"El hámster guarda semillas en los cachetes.","it":"Il criceto tiene i semi nelle guance.","ar_sy":"الهامستر بيخبّي البزر بخدودو."}],"topics":["animals"]},
{"word":"la puce","level":"A2","en":"flea","ru":"блоха","de":"der Floh","tr":"pire","es_ar":"la pulga","it":"la pulce","ar_sy":"البرغوث","examples":[{"fr":"Le chien a des puces.","en":"The dog has fleas.","ru":"У собаки блохи.","de":"Der Hund hat Flöhe.","tr":"Köpekte pire var.","es_ar":"El perro tiene pulgas.","it":"Il cane ha le pulci.","ar_sy":"الكلب عندو براغيث."},{"fr":"Une puce peut sauter très haut.","en":"A flea can jump very high.","ru":"Блоха может прыгать очень высоко.","de":"Ein Floh kann sehr hoch springen.","tr":"Bir pire çok yükseğe zıplayabilir.","es_ar":"Una pulga puede saltar muy alto.","it":"Una pulce può saltare molto in alto.","ar_sy":"البرغوث بيقدر ينطّ عالي كتير."}],"topics":["animals"]}
